939	// MobileCanResendESimActivationEmail is the resolver for the mobileCanResendESimActivationEmail field.
940	func (r *queryResolver) MobileCanResendESimActivationEmail(ctx context.Context, request *model.MobileCanResendESimActivationEmailRequest) (*model.MobileCanResendESimActivationEmailResponse, error) {
941		customerAuth, err := r.authorize(ctx, cerbos.RESEND_ESIM_ACTIVATION)
942		if err != nil {
943			return nil, err
944		}
945	
946		// Query api.
947		apiResponse, err := r.LifecycleEventCommsProcessorApiClient.GetResendableCommunications(
948			ctx,
949			&lecpPb.GetResendableCommunicationsRequest{
950				CustomerId: customerAuth.AccountID,
951			},
952		)
953		if err != nil {
954			return nil, err
955		}
956	
957		// Identify esim activation communication for this service from returned comms.
958		var esimComm *lecpPb.ResendableCommunication
959		for _, comm := range apiResponse.Resendable {
960			if comm.Type == lecpPb.ResendableType_RESENDABLE_TYPE_ESIM_ACTIVATION_EMAIL &&
961				(comm.ServiceId != nil && *comm.ServiceId == request.ServiceID) {
962				esimComm = comm
963				break
964			}
965		}
966		if esimComm == nil {
967			return &model.MobileCanResendESimActivationEmailResponse{
968				Resendable: false,
969			}, nil
970		}
971	
972		// Build response.
973		response := &model.MobileCanResendESimActivationEmailResponse{
974			Resendable: esimComm.Resendable,
975		}
976		if esimComm.NextSend != nil {
977			nextSendStr := utils.TimestampbbToString(esimComm.NextSend)
978			response.NextSend = &nextSendStr
979		}
980		if esimComm.ExpiresAt != nil {
