	}

	req := &quotingapi.SubmitQuoteV2Request{
		QuoteId: request.QuoteID,
		Subject: customerAuth.AccountNumber,
	}

	_, err = r.QuotingClient.SubmitQuoteV2(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("could not submit quote: %w", err)
	}

	return &sharedmodel.MobileAddSimSubmitQuoteResponse{Success: true}, nil
}

