// MobileActivateSim is the resolver for the mobileActivateSim field.
func (r *mutationResolver) MobileActivateSim(ctx context.Context, request model.MobileActivateSimRequest) (*model.MobileActivateSimResponse, error) {
	customerAuth, err := r.authorize(ctx, cerbos.ACTIVATE_SIM)
	if err != nil {
		return nil, err
	}

	switch {
	case request.ServiceID != nil && *request.ServiceID != "":
		return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("not implemented: use service cli, for now")
	case request.Cli != nil && *request.Cli != "":
		res, err := r.SimActivationApiClient.GetUnactivatedSims(ctx, &simactivationservice.GetUnactivatedSimsRequest{AccountNumber: customerAuth.AccountNumber})
		if err != nil {
			return &model.MobileActivateSimResponse{Success: false}, err
		}

		for _, sim := range res.GetSims() {
			// If we can find a matching sim that belongs to the mobile platform (has a ServiceID), then we should
			// activate using the Activate rpc. Otherwise, we should activate using the ActivateLegacy rpc.
			if sim.GetMsisdn() == *request.Cli && sim.GetServiceId() != "" {
				_, err = r.SimActivationApiClient.Activate(ctx, &simactivationservice.ActivateRequest{
					ServiceId: sim.GetServiceId(),
					Source:    simactivationservice.ActivationSource_SOURCE_MYACCOUNT,
				})
				if err != nil {
					return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("could not activate platform sim: %w", err)
				}

				return &model.MobileActivateSimResponse{Success: true}, nil
			}
		}

		_, err = r.SimActivationApiClient.ActivateLegacy(ctx, &simactivationservice.ActivateLegacyRequest{
			AccountNumber: customerAuth.AccountNumber,
			Msisdn:        *request.Cli,
			Source:        simactivationservice.ActivationSource_SOURCE_MYACCOUNT,
		})
		if err != nil {
			return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("could not activate legacy sim: %w", err)
		}
	default:
		return &model.MobileActivateSimResponse{Success: false}, fmt.Errorf("either service id or cli is required")
	}

	return &model.MobileActivateSimResponse{Success: true}, nil
}

