func (r *mutationResolver) MobilePortingVerifiedPortOut(ctx context.Context, req model.MobilePortingOutVerifiedPortOutRequest) (*model.MobilePortingOutVerifiedPortOutResponse, error) {
	customerAuth, err := r.authorize(ctx, cerbos.PORT_OUT)
	if err != nil {
		return nil, err
	}

	permitted, err := r.isServiceOwnedByCustomer(ctx, *customerAuth, req.ServiceID)
	if err != nil {
		return nil, terrors.ErrInternalServerErr
	}
	if !permitted {
		return nil, terrors.ErrAccessDenied
	}

	_, err = r.PortingServiceClient.VerifyOTPCode(ctx, &portingservice.VerifyOTPCodeRequest{
		ServiceId:           req.ServiceID,
		DonorCli:            req.PortRequest.Cli,
		OtpVerificationCode: req.OtpVerificationCode,
	})
	if err != nil {
		return nil, fmt.Errorf("could not verify port in: %w", err)
	}

	request, err := r.toDomainMobilePortingRequest(req.PortRequest)
	if err != nil {
		return nil, fmt.Errorf("unable to create mobile porting request: %w", err)
	}

	portingResponse, err := r.PortingOutClient.MobilePortingRequest(ctx, request)
	if err != nil {
		return nil, status.Errorf(codes.Internal, "unable to carry a porting request forward: %v", err)
	}

	if portingResponse.ErrorMessage != "" {
		msg := func() *sharedmodel.MobilePortingOutErrors {
			switch portingResponse.ErrorMessage {
			case string(sharedmodel.STAC_ALREADY_EXISTS):
				stacErr := sharedmodel.STAC_ALREADY_EXISTS
				return &stacErr
			case string(sharedmodel.PAC_ALREADY_EXISTS):
				pacErr := sharedmodel.PAC_ALREADY_EXISTS
				return &pacErr
			default:
				return nil
			}
		}()

		return &model.MobilePortingOutVerifiedPortOutResponse{
				Response:     nil,
				ErrorMessage: msg,
			},
			nil
	}

	return &model.MobilePortingOutVerifiedPortOutResponse{
		Response: r.toPacResponse(portingResponse),
	}, nil
}

