// MobileRequestSimReplacement is the resolver for the mobileRequestSimReplacement field.
func (r *mutationResolver) MobileRequestSimReplacement(ctx context.Context, request model.MobileSimReplacementRequest) (*model.MobileSimReplacementResponse, error) {
	auth, err := r.authorize(ctx, cerbos.REPLACE_SIM)
	if err != nil {
		return nil, err
	}

	overrideAddress := r.getOverrideAddress(request)

	reason, err := graphqlshared.ParseReplacementReason(request.Reason)
	if err != nil {
		return nil, fmt.Errorf("unable to parse replacement reason: %w", err)
	}

	simType := graphqlshared.ConvertSimType(request.SimType)

	resp, err := r.SimReplacementClient.RequestSimReplacement(ctx, &simreplacementservice.RequestSimReplacementRequest{
		AccountNumber:   auth.AccountNumber,
		Cli:             request.Cli,
		Reason:          reason,
		OverrideAddress: overrideAddress,
		Channel:         new(AuditChannel),
		SimType:         simType,
	})
	if err != nil {
		if strings.Contains(err.Error(), replaceerrors.ErrPhoneChangedRecently.Error()) ||
			strings.Contains(err.Error(), replaceerrors.ErrEmailChangedRecently.Error()) {
			errorMessage := model.MobileSimReplacementErrorReasonContactDetailsChangedRecently
			return &model.MobileSimReplacementResponse{
				ErrorMessage: &errorMessage,
			}, nil
		}
		return nil, fmt.Errorf("unable to request sim replacement: %w", err)
	}

	return &model.MobileSimReplacementResponse{
		SimBarred:             resp.SimBarred,
		SimReplacementOrdered: resp.SimReplacementOrdered,
		SimReplacementOnHold:  resp.SimReplacementOnHold,
	}, nil
}

