	if err != nil {
		return nil, fmt.Errorf("could not get quote: %w", err)
	}

	// Validate the quote actually belongs to the customer
	if resp.CustomerAccountNumber != customerAuth.AccountNumber {
		return nil, terrors.ErrPermissionDenied
	}

	// getting email from A&I
	account, err := r.AccountApiClient.GetAccount(ctx, &accountapi.GetAccountRequest{AccountId: customerAuth.AccountID})
	if err != nil {
		return nil, err
	}

	return r.SharedResolver.MobileGenerateAndEmailEeccContract(ctx, graphqlshared.MobileGenerateAndEmailEeccContractRequest{
		AccountID:    customerAuth.AccountID,
		QuoteID:      resp.QuoteId,
		EmailAddress: account.GetAccount().GetPrimaryAccountHolder().GetEmail(),
	})
}

