// MobileValidateOTPVerificationCode is the resolver for the mobileValidateOTPVerificationCode field.
func (r *queryResolver) MobileValidateOTPVerificationCode(ctx context.Context, request model.MobileValidateOTPVerificationCodeRequest) (*model.MobileValidateOTPVerificationCodeResponse, error) {
	customerAuth, err := r.authorize(ctx, cerbos.PORT_VALIDATE_PAC)
	if err != nil {
		return nil, err
	}

	permitted, err := r.isServiceOwnedByCustomer(ctx, *customerAuth, request.ServiceID)
	if err != nil {
		return nil, terrors.ErrInternalServerErr
	}
	if !permitted {
		return nil, terrors.ErrAccessDenied
	}

	_, err = r.PortingServiceClient.VerifyOTPCode(ctx, &portingservice.VerifyOTPCodeRequest{
		ServiceId:           request.ServiceID,
		DonorCli:            request.Cli,
		OtpVerificationCode: request.OtpCode,
	})
	if err != nil {
		return nil, fmt.Errorf("unable to verify otp: %w", err)
	}
	res, err := r.PortingOutClient.GetCachedPortingCode(ctx, &portingoutservice.GetCachedPortingCodeRequest{
		Cli: request.Cli,
	})
	if err != nil {
		// This is normal, porting code not found or expired, so we shouldn't return an error in that case
		if !strings.Contains(err.Error(), portingouterrors.ErrAuthCodeNotFound.Error()) {
			return nil, fmt.Errorf("unable to get auth code: %w", err)
		}
	}

	return &model.MobileValidateOTPVerificationCodeResponse{
		Success:     true,
		PortingInfo: toPortingInfo(res),
	}, nil
}

