// MobileCanResendESimActivationEmail is the resolver for the mobileCanResendESimActivationEmail field.
func (r *queryResolver) MobileCanResendESimActivationEmail(ctx context.Context, request *model.MobileCanResendESimActivationEmailRequest) (*model.MobileCanResendESimActivationEmailResponse, error) {
	customerAuth, err := r.authorize(ctx, cerbos.RESEND_ESIM_ACTIVATION)
	if err != nil {
		return nil, err
	}

	// Query api.
	apiResponse, err := r.LifecycleEventCommsProcessorApiClient.GetResendableCommunications(
		ctx,
		&lecpPb.GetResendableCommunicationsRequest{
			CustomerId: customerAuth.AccountID,
		},
	)
	if err != nil {
		return nil, err
	}

	// Identify esim activation communication for this service from returned comms.
	var esimComm *lecpPb.ResendableCommunication
	for _, comm := range apiResponse.Resendable {
		if comm.Type == lecpPb.ResendableType_RESENDABLE_TYPE_ESIM_ACTIVATION_EMAIL &&
			(comm.ServiceId != nil && *comm.ServiceId == request.ServiceID) {
			esimComm = comm
			break
		}
	}
	if esimComm == nil {
		return &model.MobileCanResendESimActivationEmailResponse{
			Resendable: false,
		}, nil
	}

	// Build response.
	response := &model.MobileCanResendESimActivationEmailResponse{
		Resendable: esimComm.Resendable,
	}
	if esimComm.NextSend != nil {
		nextSendStr := utils.TimestampbbToString(esimComm.NextSend)
		response.NextSend = &nextSendStr
	}
	if esimComm.ExpiresAt != nil {
		expiresAtStr := utils.TimestampbbToString(esimComm.ExpiresAt)
		response.ExpiresAt = &expiresAtStr
	}
	return response, nil
}

// Mutation returns model.MutationResolver implementation.
func (r *Resolver) Mutation() model.MutationResolver { return &mutationResolver{r} }

// Query returns model.QueryResolver implementation.
func (r *Resolver) Query() model.QueryResolver { return &queryResolver{r} }

type mutationResolver struct{ *Resolver }
type queryResolver struct{ *Resolver }
